refsection.programlisting:
left = imread(fullpath(getIPCVpath() + "/images/opencv_left01.jpg"));
right = imread(fullpath(getIPCVpath() + "/images/opencv_left02.jpg"));
leftFeatures = imdetect_KAZE(left);
rightFeatures = imdetect_KAZE(right);
leftDescriptors = imextract_DescriptorKAZE(left, leftFeatures);
rightDescriptors = imextract_DescriptorKAZE(right, rightFeatures);
disp([size(leftDescriptors, 1) size(rightDescriptors, 1)]);

image = imread(fullpath(getIPCVpath() + "/images/opencv_smarties.png"));
features = imdetect_KAZE(image);
descriptors = imextract_DescriptorKAZE(image, features);
disp([features.n size(descriptors, 1) size(descriptors, 2)]);
